import plotly.express as px
from dash import Dash, dcc, html, Output, Input
import pandas as pd
import numpy as np

np.random.seed(42)

def generate_synthetic_plant_data():
    category_list = ['setosa', 'versicolor', 'virginica']
    data = []

    for category in category_list:
        for _ in range(20):
            if category == 'setosa':
                dim_a = np.random.normal(5.0, 0.35)
                dim_b = np.random.normal(3.4, 0.38)
            elif category == 'versicolor':
                dim_a = np.random.normal(5.9, 0.52)
                dim_b = np.random.normal(2.8, 0.31)
            else:
                dim_a = np.random.normal(6.5, 0.64)
                dim_b = np.random.normal(3.0, 0.33)

            data.append({
                'dimension_a': max(4.0, min(8.0, dim_a)),
                'dimension_b': max(2.0, min(4.5, dim_b)),
                'category': category
            })

    return pd.DataFrame(data)

df = generate_synthetic_plant_data()

categories = df["category"].unique().tolist()

options = [{"label": cat.capitalize(), "value": cat} for cat in categories[:3]]

app = Dash(__name__)

app.layout = html.Div(
    [
        dcc.Checklist(
            options=options,
            inline=True,
            value=categories,
            id="checklist-plots-x-checklist",
        ),
        dcc.Graph(id="checklist-plots-x-scatter"),
    ]
)

@app.callback(
    Output("checklist-plots-x-scatter", "figure"),
    Input("checklist-plots-x-checklist", "value"),
)
def update_figure(values):
    fig = px.scatter(
        df[df["category"].isin(values)],
        x="dimension_a",
        y="dimension_b",
        color="category",
    )
    return fig

if __name__ == "__main__":
    app.run(debug=True)

