    Output("dynamic-callback-x-line", "figure"),
    Input("dynamic-callback-x-country", "value"),
    Input("dynamic-callback-x-state", "value"),
    Input("dynamic-callback-x-region", "value"),
)
def line_chart(country, state, region):
